files./src/SearchBar.js:
import React, { useState, useEffect, useMemo } from 'react';

const DATA = [
  'Apple', 'Banana', 'Blueberry', 'Cherry', 'Date', 'Elderberry',
  'Fig', 'Grape', 'Kiwi', 'Lemon', 'Mango', 'Orange', 'Papaya', 'Peach',
];

function useDebounced(value, delay = 300) {
  const [v, setV] = useState(value);
  useEffect(() => {
    const id = setTimeout(() => setV(value), delay);
    return () => clearTimeout(id);
  }, [value, delay]);
  return v;
}

export default function SearchBar() {
  const [text, setText] = useState('');
  const query = useDebounced(text, 300);

  const results = useMemo(
    () => DATA.filter((d) => d.toLowerCase().includes(query.trim().toLowerCase())),
    [query]
  );

  const pending = text !== query;

  return (
    <div style={{ maxWidth: 360 }}>
      <input
        value={text}
        onChange={(e) => setText(e.target.value)}
        placeholder="Search fruit…"
        style={{ width: '100%', padding: 10, fontSize: 15, boxSizing: 'border-box' }}
      />
      <div style={{ minHeight: 18, color: '#888', fontSize: 13, margin: '6px 0' }}>
        {pending ? 'searching…' : `${results.length} result(s) for "${query}"`}
      </div>
      <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
        {results.map((r) => (
          <li key={r} style={{ padding: '6px 0', borderBottom: '1px solid #eee' }}>{r}</li>
        ))}
      </ul>
    </div>
  );
}

angular.answer:
## Building a Debounced Search Bar in Angular

**Mental model:** Keep the input responsive on every keystroke, but only *act* once typing pauses. Hold the raw text and a debounced query as fields; on each input, reset a timer that mirrors the value after N ms. Derive results with a getter. Classic `NgModule` setup — no signals/standalone, no `?.`/`??` (the build rejects them), and no `FormsModule`.

### Step 1 — Raw + debounced fields
```typescript
text = '';
query = '';
private timer: any = null;
```

### Step 2 — Debounce on input
```typescript
onInput(value: string): void {
  this.text = value;
  clearTimeout(this.timer);
  this.timer = setTimeout(() => { this.query = value; }, 300);
}
```

### Step 3 — Derive results with a getter
```typescript
get results(): string[] {
  const q = this.query.trim().toLowerCase();
  return this.data.filter((d) => d.toLowerCase().indexOf(q) !== -1);
}
```

### Step 4 — Show pending + clean up
`pending` is just `text !== query`; clear the timer in `ngOnDestroy`.

```typescript
get pending(): boolean { return this.text !== this.query; }
ngOnDestroy(): void { clearTimeout(this.timer); }
```

**Edge cases**

| Case | Handling |
| :-- | :-- |
| Rapid typing | `clearTimeout` keeps only the last scheduled update. |
| Destroy mid-debounce | `ngOnDestroy` clears the timer. |
| RxJS alternative | In real apps, `fromEvent` + `debounceTime` + `switchMap` cancels stale requests. |

**Interview tip:** Mention that the RxJS idiom (`debounceTime` + `switchMap`) is the production Angular answer — `switchMap` cancels the in-flight request when a newer query arrives, solving the async race for free.

