import { Component, OnDestroy } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-search-bar',
  template: `
    <div style="max-width: 360px;">
      <input
        (input)="onInput($any($event.target).value)"
        placeholder="Search fruit…"
        style="width: 100%; padding: 10px; font-size: 15px; box-sizing: border-box;"
      />
      <div style="min-height: 18px; color: #888; font-size: 13px; margin: 6px 0;">
        <span *ngIf="pending">searching…</span>
        <span *ngIf="!pending">{{ results.length }} result(s) for "{{ query }}"</span>
      </div>
      <ul style="list-style: none; padding: 0; margin: 0;">
        <li *ngFor="let r of results" style="padding: 6px 0; border-bottom: 1px solid #eee;">{{ r }}</li>
      </ul>
    </div>
  `,
})
export class SearchBarComponent implements OnDestroy {
  text = '';
  query = '';
  private timer: any = null;
  data = [
    'Apple', 'Banana', 'Blueberry', 'Cherry', 'Date', 'Elderberry',
    'Fig', 'Grape', 'Kiwi', 'Lemon', 'Mango', 'Orange', 'Papaya', 'Peach',
  ];

  onInput(value: string): void {
    this.text = value;
    clearTimeout(this.timer);
    this.timer = setTimeout(() => {
      this.query = value;
    }, 300);
  }

  get results(): string[] {
    const q = this.query.trim().toLowerCase();
    return this.data.filter((d) => d.toLowerCase().indexOf(q) !== -1);
  }

  get pending(): boolean {
    return this.text !== this.query;
  }

  ngOnDestroy(): void {
    clearTimeout(this.timer);
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Debounced Search Demo</h1>
      <app-search-bar></app-search-bar>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, SearchBarComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
